import React, { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Appointment() {
  const location = useLocation();
  const navigate = useNavigate();

  const { doctor, date, time, doctor_id } = location.state || {};

  const [popup, setPopup] = useState({ show: false, message: "" });
  const [loading, setLoading] = useState(false);

  // ❌ If page refreshed or no data
  if (!doctor) {
    return (
      <div style={styles.center}>
        <h2>No Appointment Data Found</h2>
        <button onClick={() => navigate("/doctorslist")}>
          Go Back
        </button>
      </div>
    );
  }

  // ✅ CONFIRM BOOKING
  const handleConfirm = async () => {
    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/login");
      return;
    }

    setLoading(true);

    try {
      const response = await fetch(
        "http://127.0.0.1:8000/book-appointment/",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Token ${token}`,
          },
          body: JSON.stringify({
            doctor_id: doctor_id,
            appointment_date: date,
            time_slot: time,
          }),
        }
      );

      const data = await response.json();

      if (response.ok) {
        setPopup({
          show: true,
          message: "Appointment booked successfully!",
        });

        setTimeout(() => {
          navigate("/myappointments");
        }, 1500);
      } else {
        setPopup({
          show: true,
          message: data.error || "Booking failed",
        });
      }
    } catch (error) {
      setPopup({
        show: true,
        message: "Server error. Try again later.",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <Navbar />

      {/* POPUP */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <p>{popup.message}</p>
            <button
              style={styles.popupBtn}
              onClick={() => setPopup({ show: false, message: "" })}
            >
              OK
            </button>
          </div>
        </div>
      )}

      <div style={styles.main}>
        <div style={styles.card}>
          <h2>Confirm Appointment</h2>

          <div style={styles.infoBox}>
            <p><b>Doctor:</b> {doctor.name}</p>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Date:</b> {date}</p>
            <p><b>Time:</b> {time}</p>
          </div>

          <button
            style={styles.button}
            onClick={handleConfirm}
            disabled={loading}
          >
            {loading ? "Booking..." : "Confirm Booking"}
          </button>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Appointment;

/* STYLES */
const styles = {
  container: {
    minHeight: "100vh",
    background: "#f4f6f9",
    display: "flex",
    flexDirection: "column",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  card: {
    background: "#fff",
    padding: "30px",
    borderRadius: "10px",
    width: "400px",
    textAlign: "center",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },

  infoBox: {
    textAlign: "left",
    marginTop: "15px",
    marginBottom: "20px",
    lineHeight: "1.8",
  },

  button: {
    width: "100%",
    padding: "10px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },

  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  popupCard: {
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
    textAlign: "center",
  },

  popupBtn: {
    marginTop: "10px",
    padding: "5px 15px",
  },

  center: {
    textAlign: "center",
    marginTop: "100px",
  },
};
